const express = require('express');
const jwt = require('jsonwebtoken');
const session = require('express-session');
const bodyParser = require('body-parser');
const axios = require('axios');

const app = express();
const port = 3000;

// Secure session management
app.use(session({
  secret: 'your-secure-session-secret',
  resave: false,
  saveUninitialized: true,
  cookie: { secure: true, httpOnly: true, sameSite: 'strict' }
}));

app.use(bodyParser.urlencoded({ extended: false }));

// OpenID Connect configuration
const oidcConfig = {
  clientId: 'your-client-id',
  clientSecret: 'your-client-secret',
  redirectUri: 'http://localhost:3000/callback',
  authorizationEndpoint: 'https://your-oidc-provider.com/auth',
  tokenEndpoint: 'https://your-oidc-provider.com/token',
  userInfoEndpoint: 'https://your-oidc-provider.com/userinfo'
};

// Redirect to OpenID Provider for authentication
app.get('/login', (req, res) => {
  const authUrl = `${oidcConfig.authorizationEndpoint}?response_type=code&client_id=${encodeURIComponent(oidcConfig.clientId)}&redirect_uri=${encodeURIComponent(oidcConfig.redirectUri)}&scope=openid%20profile%20email`;
  res.redirect(authUrl);
});

// Callback endpoint to handle the response from the OpenID Provider
app.get('/callback', async (req, res) => {
  const code = req.query.code;
  if (!code) {
    return res.status(400).send('Invalid request');
  }

  try {
    // Exchange authorization code for tokens
    const tokenResponse = await axios.post(oidcConfig.tokenEndpoint, null, {
      params: {
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: oidcConfig.redirectUri,
        client_id: oidcConfig.clientId,
        client_secret: oidcConfig.clientSecret
      }
    });

    const idToken = tokenResponse.data.id_token;
    if (!idToken) {
      return res.status(400).send('ID token not received');
    }

    // Decode ID token to extract user claims
    const decodedToken = jwt.decode(idToken, { complete: true });
    if (!decodedToken) {
      return res.status(400).send('Failed to decode ID token');
    }

    const userClaims = decodedToken.payload;

    // Create user session
    req.session.user = {
      id: userClaims.sub,
      email: userClaims.email,
      name: userClaims.name
    };

    res.send('Login successful');
  } catch (error) {
    console.error('Error during authentication:', error);
    res.status(500).send('Internal Server Error');
  }
});

// Logout endpoint
app.get('/logout', (req, res) => {
  req.session.destroy(err => {
    if (err) {
      return res.status(500).send('Failed to logout');
    }
    res.send('Logout successful');
  });
});

app.listen(port, () => {
  console.log(`Server running at http://localhost:${port}`);
});